+    for dir_name in AUXILIARY_EXTENSION_DIR_NAMES {
+        let candidate_dir = package_dir.join(dir_name);
+        for candidate in collect_extension_entries_from_dir(&candidate_dir) {
+            if &candidate == canonical_primary {
